module serial2parallel (
    input clk,
    input rst_n,
    input din_serial,
    input din_valid,
    output reg [7:0]dout_parallel,
    output reg dout_valid
);
reg [3:0] cnt;
reg [7:0] data;
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        cnt <= 4'b0000;
        data <= 8'b0;
        dout_parallel <= 8'b0;
        dout_valid <= 1'b0;
    end
    else begin
        if (din_valid) begin
            data <= {data[6:0], din_serial};
            cnt <= cnt + 4'b0001;
            if (cnt == 4'b1000) begin
                dout_parallel <= data;
                dout_valid <= 1'b1;
            end
            else begin
                dout_valid <= 1'b0;
            end
        end
        else begin
            dout_valid <= 1'b0;
        end
    end
end
endmodule

module width_8to16 (
    input 				   clk,
    input 				   rst_n,
    input				      valid_in,
    input	   [7:0]		   data_in,
    output	reg			valid_out,
    output   reg [15:0]	data_out
);

reg [7:0] data_lock;
reg flag;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        data_out <= 16'b0;
        valid_out <= 1'b0;
        flag <= 1'b0;
    end else begin
        if (valid_in) begin
            if (flag) begin
                data_out <= {data_lock, data_in};
                valid_out <= 1'b1;
                flag <= 1'b0;
            end else begin
                data_lock <= data_in;
                flag <= 1'b1;
                valid_out <= 1'b0;
            end
        end else begin
            valid_out <= 1'b0;
        end
    end
end

endmodule

module sub_64bit (
    input [63:0] A,
    input [63:0] B,
    output reg [63:0] result,
    output reg overflow
);

assign result = A - B;

assign overflow = ((A[63] == 0 && B[63] == 1 && result[63] == 1) || (A[63] == 1 && B[63] == 0 && result[63] == 0)) ? 1'b1 : 1'b0;
endmodule

module traffic_light #(
    parameter idle = 2'd0,
    parameter s1_red = 2'd1,
    parameter s2_yellow = 2'd2,
    parameter s3_green = 2'd3
) (
    input rst_n,
    input clk,
    input pass_request,
    output wire[7:0]clock,
    output reg red,
    output reg yellow,
    output reg green
);
reg [7:0] cnt;
reg [1:0] state;
reg p_red, p_yellow, p_green;
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        state <= idle;
        cnt <= 8'd0;
        red <= 1'b0;
        yellow <= 1'b0;
        green <= 1'b0;
    end
    else begin
        case (state)
            idle: begin
                red <= 1'b0;
                yellow <= 1'b0;
                green <= 1'b0;
                cnt <= 8'd0;
                state <= s1_red;
            end
            s1_red: begin
                red <= 1'b1;
                yellow <= 1'b0;
                green <= 1'b0;
                if (cnt == 8'd3) begin
                    state <= s2_yellow;
                    cnt <= 8'd0;
                end
                else begin
                    cnt <= cnt + 8'd1;
                end
            end
            s2_yellow: begin
                red <= 1'b0;
                yellow <= 1'b1;
                green <= 1'b0;
                if (cnt == 8'd3) begin
                    state <= s3_green;
                    cnt <= 8'd0;
                end
                else begin
                    cnt <= cnt + 8'd1;
                end
            end
            s3_green: begin
                red <= 1'b0;
                yellow <= 1'b0;
                green <= 1'b1;
                if (cnt == 8'd3) begin
                    state <= s2_yellow;
                    cnt <= 8'd0;
                end
                else begin
                    cnt <= cnt + 8'd1;
                end
            end
            default: begin
                state <= idle;
            end
        endcase
    end
end
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        p_red <= 1'b0;
        p_yellow <= 1'b0;
        p_green <= 1'b0;
    end
    else begin
        p_red <= red;
        p_yellow <= yellow;
        p_green <= green;
    end
end
assign clock = cnt;
endmodule

module fixed_point_adder #(
    parameter Q = 15,
    parameter N = 32
) (
    input [N-1:0] a,
    input [N-1:0] b,
    output [N-1:0] c
);

reg [N-1:0] res;

assign c = res;

always @* begin

    res = 0;

    if (a[N-1] == b[N-1]) begin

        res = a + b;

        res[N-1] = a[N-1];
    end else begin

        if (a > b) begin
            res = a - b;
            res[N-1] = 0; 
        end else if (b > a) begin
            res = b - a;
            res[N-1] = (res != 0) ? 1 : 0; 
        end
    end
end
endmodule

module multi_16bit (
    input clk,
    input rst_n,
    input start,
    input [15:0] ain,
    input [15:0] bin,
    output reg [31:0] yout,
    output reg done
);

    reg [15:0] areg, breg;
    reg [31:0] yout_r;
    reg [4:0] i;
    reg done_r;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            i <= 0;
        end else if (start && i < 17) begin
            i <= i + 1;
        end else if (!start) begin
            i <= 0;
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            done_r <= 0;
        end else if (i == 16) begin
            done_r <= 1;
        end else if (i == 17) begin
            done_r <= 0;
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            areg <= 0;
            breg <= 0;
            yout_r <= 0;
        end else if (start) begin
            areg <= ain;
            breg <= bin;
            yout_r <= 0;
        end else begin
            if (i <= 16) begin
                yout_r <= yout_r + (breg[i-1] ? (areg << (i-1)) : 0);
            end
        end
    end

    always @(*) begin
        yout = yout_r;
        done = done_r;
    end

endmodule

module multi_pipe_8bit #(
    parameter size = 8
) (
    input clk,
    input rst_n,
    input [size-1:0] mul_a,
    input [size-1:0] mul_b,
    input mul_en_in,
    output reg mul_en_out,
    output reg [size*2-1:0] mul_out
);

reg [2:0] mul_en_out_reg;
reg [7:0] mul_a_reg, mul_b_reg;
reg [15:0] mul_out_reg;
reg [15:0] temp [7:0];
reg [15:0] sum [3:0];

always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        mul_en_out_reg <= 0;
        mul_en_out <= 0;
    end
    else begin
        mul_en_out_reg <= {mul_en_out_reg[1:0], mul_en_in};
        mul_en_out <= mul_en_out_reg[2];
    end
end

always @(posedge clk) begin
    if(mul_en_in) begin
        mul_a_reg <= mul_a;
        mul_b_reg <= mul_b;
    end
    else begin
        mul_a_reg <= 0;
        mul_b_reg <= 0;
    end
end

always @(posedge clk) begin
    for(integer i = 0; i < 8; i=i+1) begin
        if(mul_en_out_reg[2])
            temp[i] <= mul_a_reg[i] ? (mul_b_reg << i) : 0;
            temp[i] <= 0;
    end
end

always @(posedge clk) begin
    if(mul_en_out_reg[2]) begin
        sum[0] <= temp[0] + temp[1];
        sum[1] <= temp[2] + temp[3];
        sum[2] <= temp[4] + temp[5];
        sum[3] <= temp[6] + temp[7];
    end
    else begin
        sum[0] <= 0;
        sum[1] <= 0;
        sum[2] <= 0;
        sum[3] <= 0;
    end
end

always @(posedge clk) begin
    if(mul_en_out_reg[2]) begin
        mul_out_reg <= sum[0] + sum[1] + sum[2] + sum[3];
    end
    else begin
        mul_out_reg <= 0;
    end
end

always @(posedge clk) begin
    if(mul_en_out_reg[2]) begin
        mul_out <= mul_out_reg;
    end
    else begin
        mul_out <= 0;
    end
end

endmodule

module freq_divbyfrac #(
    parameter MUL2_DIV_CLK = 7
) (
    input               rst_n,
    input               clk,
    output              clk_div
);
parameter DIV_CLK = MUL2_DIV_CLK / 2;
parameter DIV_CLK_ADV = DIV_CLK + 1;
reg [2:0] cnt;
reg div_clk;
reg div_clk_adv;
reg div_clk_half;
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        cnt <= 0;
        div_clk <= 0;
        div_clk_adv <= 0;
        div_clk_half <= 0;
    end else begin
        if (cnt == MUL2_DIV_CLK - 1) begin
            cnt <= 0;
            div_clk <= ~div_clk;
            div_clk_adv <= ~div_clk_adv;
        end else begin
            cnt <= cnt + 1;
        end
        if (cnt == DIV_CLK - 1) begin
            div_clk_half <= ~div_clk_half;
        end
    end
end
assign clk_div = div_clk | div_clk_adv;
endmodule

module parallel2serial (
    input wire clk,
    input wire rst_n,
    input wire [3:0]d,
    output wire valid_out,
    output wire dout
);

reg [1:0] cnt;
reg [3:0] data;
reg valid;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        cnt <= 2'b00;
        data <= 4'b0000;
        valid <= 1'b0;
    end
    else begin
        if (cnt == 2'b11) begin
            data <= d;
            cnt <= 2'b00;
            valid <= 1'b1;
        end
        else begin
            data <= {data[2:0], data[3]};
            cnt <= cnt + 2'b01;
            valid <= 1'b0;
        end
    end
end

assign dout = data[3];
assign valid_out = valid;

endmodule

module float_multi (
    input clk,
    input rst,
    input [31:0] a,
    input [31:0] b,
    output reg [31:0] z
);

reg [2:0] counter;
reg [23:0] a_mantissa, b_mantissa, z_mantissa;
reg [9:0] a_exponent, b_exponent, z_exponent;
reg a_sign, b_sign, z_sign;
reg [49:0] product;
reg guard_bit, round_bit, sticky;

always @(posedge clk) begin
    if (rst) begin
        counter <= 0;
        a_mantissa <= 0;
        b_mantissa <= 0;
        z_mantissa <= 0;
        a_exponent <= 0;
        b_exponent <= 0;
        z_exponent <= 0;
        a_sign <= 0;
        b_sign <= 0;
        z_sign <= 0;
        product <= 0;
        guard_bit <= 0;
        round_bit <= 0;
        sticky <= 0;
        z <= 0;
    end else begin
        case (counter)
            0: begin
                a_mantissa <= {1'b1, a[22:0]};
                b_mantissa <= {1'b1, b[22:0]};
                a_exponent <= a[30:23] - 127;
                b_exponent <= b[30:23] - 127;
                a_sign <= a[31];
                b_sign <= b[31];
                counter <= 1;
            end
            1: begin
                if ((a_exponent == 128 && a_mantissa != 0) || (b_exponent == 128 && b_mantissa != 0)) begin
                    z <= 255;
                    counter <= 2;
                end else begin
                    if (a_exponent == 0 || b_exponent == 0) begin
                        z <= 0;
                        counter <= 2;
                    end else begin
                        z_sign <= a_sign ^ b_sign;
                        product <= a_mantissa * b_mantissa;
                        counter <= 2;
                    end
                end
            end
            2: begin
                if (product[49]) begin
                    z_mantissa <= product[48:25];
                    z_exponent <= a_exponent + b_exponent;
                end else begin
                    z_mantissa <= product[47:24];
                    z_exponent <= a_exponent + b_exponent - 1;
                end
                counter <= 3;
            end
            3: begin
                guard_bit <= product[24];
                round_bit <= product[23];
                sticky <= |product[22:0];
                counter <= 4;
            end
            4: begin
                if (guard_bit && (round_bit || sticky)) begin
                    z_mantissa <= z_mantissa + 1;
                    if (z_mantissa == 256) begin
                        z_exponent <= z_exponent + 1;
                        if (z_exponent == 255) begin
                            z <= 255;
                        end
                    end
                end
                counter <= 5;
            end
            5: begin
                if (z_exponent == 0) begin
                    z <= 0;
                end else begin
                    z <= {z_sign, z_exponent[7:0], z_mantissa[22:0]};
                end
                counter <= 0;
            end
        endcase
    end
end

endmodule

module comparator_3bit (
    input [2:0] A,
    input [2:0] B,
    output A_greater,
    output A_equal,
    output A_less
);

assign A_greater = (A > B) ? 1'b1 : 1'b0;
assign A_equal = (A == B) ? 1'b1 : 1'b0;
assign A_less = (A < B) ? 1'b1 : 1'b0;
endmodule

module div_16bit (
    input wire [15:0] A,
    input wire [7:0] B,
    output reg [15:0] result,
    output reg [15:0] odd
);

always @(*) begin
    if (B == 0) begin
        result = 16'b0;
        odd = A;
    end else begin
        result = A / B;
        odd = A % B;
    end
end
endmodule

module multi_8bit (
    input [7:0] A,
    input [7:0] B,
    output reg [15:0] product
);
    integer i;
    always @* begin
        product = 16'b0;
        for (i = 0; i < 8; i = i + 1) begin
            if (B[i]) begin
                product = product + (A << i);
            end
        end
    end
endmodule

module multi_booth_8bit (
    output reg [15:0] p,
    output reg rdy,
    input clk,
    input reset,
    input [7:0] a,
    input [7:0] b
);
	reg [15:0] multiplier, multiplicand;
	reg [4:0] ctr;
	always @(posedge clk or posedge (reset)) begin
		if(reset) begin
			multiplicand <= {{8{a[7]}}, a};
			multiplier <= {{8{b[7]}}, b};
			p <= 0;
			rdy <= 0;
			ctr <= 0;
		end
		else begin
			if(ctr < 16) begin
				if(multiplier[ctr])
					p <= p + multiplicand;
				multiplicand <= multiplicand << 1;
				ctr <= ctr + 1;
			end
				rdy <= 1;
		end
	end
endmodule

module barrel_shifter (
    input [7:0] in,
    input [2:0] ctrl,
    output reg [7:0] out
);

    wire [7:0] shift4, shift2, shift1;

    mux2X1 #(8) shift4_mux (.in0(in), .in1({in[3:0], in[7:4]}), .sel(ctrl[2]), .out(shift4));

    mux2X1 #(8) shift2_mux (.in0(shift4), .in1({shift4[5:0], shift4[7:6]}), .sel(ctrl[1]), .out(shift2));

    mux2X1 #(8) shift1_mux (.in0(shift2), .in1({shift2[6:0], shift2[7]}), .sel(ctrl[0]), .out(shift1));

    always @(*) begin
        out = shift1;
    end
endmodule

module mux2X1( in0,in1,sel,out);
input in0,in1;
input sel;
output out;
assign out=(sel)?in1:in0;
endmodule

module radix2_div (
    input wire clk,
    input wire rst,
    input wire [7:0] dividend,
    input wire [7:0] divisor,
    input wire sign,
    input wire opn_valid,
    output reg res_valid,
    input wire res_ready,
    output reg [15:0] result
);

    reg [7:0] dividend_reg, divisor_reg;
    reg [15:0] SR;
    reg [3:0] cnt;
    reg [7:0] NEG_DIVISOR;
    reg start_cnt;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            dividend_reg <= 0;
            divisor_reg <= 0;
            SR <= 0;
            cnt <= 0;
            NEG_DIVISOR <= 0;
            start_cnt <= 0;
            res_valid <= 0;
            result <= 0;
        end else begin
            if (opn_valid && !res_valid) begin
                dividend_reg <= dividend;
                divisor_reg <= divisor;
                SR <= {1'b0, dividend_reg} << 1;
                NEG_DIVISOR <= sign ? -divisor_reg : divisor_reg;
                start_cnt <= 1;
                cnt <= 1;
            end else if (start_cnt) begin
                if (cnt == 8) begin
                    start_cnt <= 0;
                    res_valid <= 1;
                    result <= {SR[15:8], SR[7:0]};
                end else begin
                    cnt <= cnt + 1;
                    {SR, NEG_DIVISOR} <= {SR[14:0], NEG_DIVISOR[7:0]};
                    if (SR[15]) begin
                        SR[15:8] <= SR[15:8] + NEG_DIVISOR;
                        SR[0] <= 1'b0;
                    end else begin
                        SR[0] <= 1'b1;
                    end
                end
            end else if (res_valid && res_ready) begin
                res_valid <= 0;
            end
        end
    end

endmodule

module fixed_point_substractor #(
    parameter Q = 15,
    parameter N = 32
) (
    input [N-1:0] a,
    input [N-1:0] b,
    output reg [N-1:0] c
);

reg [N-1:0] res;

always @* begin

    res = 0;

    if (a[N-1] == b[N-1]) begin

        res[N-2:Q] = a[N-2:Q] - b[N-2:Q];
        res[N-1] = a[N-1]; 
    end else begin

        if (a[N-1] > b[N-1]) begin
            res[N-2:Q] = a[N-2:Q] + ~b[N-2:Q] + 1; 
            res[N-1] = 1; 
        end else begin
            res[N-2:Q] = ~a[N-2:Q] + b[N-2:Q] + 1; 
            res[N-1] = 0; 
        end
    end

    if (res[N-2:Q] == 0 && res[N-1] != 0) begin
        res[N-1] = 0; 
    end
end

assign c = res;
endmodule

module fixed_point_subtractor #(
	parameter Q = 15,
	parameter N = 32
	)
	(
    input [N-1:0] a,
    input [N-1:0] b,
    output [N-1:0] c
    );

reg [N-1:0] res;

assign c = res;

always @(a,b) begin

	if(a[N-1] == b[N-1]) begin					
		res[N-2:0] = a[N-2:0] - b[N-2:0];		
		res[N-1] = a[N-1];							


		end												

	else if(a[N-1] == 0 && b[N-1] == 1) begin		
		if( a[N-2:0] > b[N-2:0] ) begin					
			res[N-2:0] = a[N-2:0] + b[N-2:0];			
			res[N-1] = 0;										
			end
		else begin												
			res[N-2:0] = b[N-2:0] + a[N-2:0];		
			if (res[N-2:0] == 0)
				res[N-1] = 0;									
			else
				res[N-1] = 1;									
			end
		end
	else begin												
		if( a[N-2:0] > b[N-2:0] ) begin					
			res[N-2:0] = a[N-2:0] + b[N-2:0];			
			if (res[N-2:0] == 0)
				res[N-1] = 0;										
			else
				res[N-1] = 1;										
			end
		else begin												
			res[N-2:0] = b[N-2:0] + a[N-2:0];			
			res[N-1] = 0;										
			end
		end
	end
endmodule

module fsm #(
    parameter s0 = 3'b000,
    parameter s1 = 3'b001,
    parameter s2 = 3'b010,
    parameter s3 = 3'b011,
    parameter s4 = 3'b100,
    parameter s5 = 3'b101
) (
    input IN,
    output reg MATCH,
    input CLK,
    input RST
);


reg [2:0] ST_cr, ST_nr;

reg MATCH_reg;

always @(posedge CLK or posedge RST) begin
    if (RST) begin
        ST_cr <= s0;
    end else begin
        ST_cr <= ST_nr;
    end
end

always @(*) begin
    case(ST_cr)
        s0: begin
            if(IN==1) ST_nr=s1;
            else ST_nr=s0;
        end
        s1: begin
            if(IN==1) ST_nr=s1;
            else ST_nr=s2;
        end
        s2: begin
            if(IN==1) ST_nr=s1;
            else ST_nr=s3;
        end
        s3: begin
            if(IN==1) ST_nr=s4;
            else ST_nr=s0;
        end
        s4: begin
            if(IN==1) ST_nr=s5;
            else ST_nr=s2;
        end
        s5: begin
            if(IN==1) ST_nr=s1;
            else ST_nr=s2;
        end
        default: ST_nr=s0;
    endcase
end

always @(*) begin
    if(RST) MATCH_reg=0;
    else if((ST_cr==s4)&&(IN==1)) MATCH_reg=1;
    else MATCH_reg=0;
end
assign MATCH=MATCH_reg;
endmodule

module freq_div (
    input CLK_in,
    output reg CLK_50,
    output reg CLK_10,
    output reg CLK_1,
    input RST
);
    reg [2:0] cnt_50;
    reg [3:0] cnt_10;
    reg [6:0] cnt_100;

    always @(posedge CLK_in or posedge RST) begin
        if (RST) begin
            CLK_50 <= 1'b0;
            cnt_50 <= 3'b0;
        end
        else begin
            CLK_50 <= ~CLK_50;
            cnt_50 <= cnt_50 + 1'b1;
        end
    end

    always @(posedge CLK_in or posedge RST) begin
        if (RST) begin
            CLK_10 <= 1'b0;
            cnt_10 <= 4'b0;
        end
        else begin
            if (cnt_10 == 4'd4) begin
                CLK_10 <= ~CLK_10;
                cnt_10 <= 4'b0;
            end
            else begin
                cnt_10 <= cnt_10 + 1'b1;
            end
        end
    end

    always @(posedge CLK_in or posedge RST) begin
        if (RST) begin
            CLK_1 <= 1'b0;
            cnt_100 <= 7'b0;
        end
        else begin
            if (cnt_100 == 7'd49) begin
                CLK_1 <= ~CLK_1;
                cnt_100 <= 7'b0;
            end
            else begin
                cnt_100 <= cnt_100 + 1'b1;
            end
        end
    end
endmodule

module alu #(
    parameter ADD = 6'b100000,
    parameter ADDU = 6'b100001,
    parameter SUB = 6'b100010,
    parameter SUBU = 6'b100011,
    parameter AND = 6'b100100,
    parameter OR = 6'b100101,
    parameter XOR = 6'b100110,
    parameter NOR = 6'b100111,
    parameter SLT = 6'b101010,
    parameter SLTU = 6'b101011,
    parameter SLL = 6'b000000,
    parameter SRL = 6'b000010,
    parameter SRA = 6'b000011,
    parameter SLLV = 6'b000100,
    parameter SRLV = 6'b000110,
    parameter SRAV = 6'b000111,
    parameter JR = 6'b001000,
    parameter LUI = 6'b001111
) (
    input [31:0] a,
    input [31:0] b,
    input [5:0] aluc,
    output [31:0] r,
    output zero,
    output carry,
    output negative,
    output overflow,
    output flag
);

    reg [32:0] res;
    wire signed [31:0] signed_a, signed_b;
    assign signed_a = a;
    assign signed_b = b;

    assign r = res[31:0];
    assign zero = &res[31:0];
    assign carry = res[32];
    assign negative = signed_a[31];
    assign overflow = (aluc == ADD || aluc == SUB) ? ((signed_a[31] == signed_b[31]) && (signed_a[31] != res[31])) : 1'b0;
    assign flag = (aluc == SLT || aluc == SLTU) ? res[31] : 1'bz;

    always @(*) begin
        case (aluc)
            ADD: res = signed_a + signed_b;
            ADDU: res = a + b;
            SUB: res = signed_a - signed_b;
            SUBU: res = a - b;
            AND: res = {1'b0, a & b};
            OR: res = {1'b0, a | b};
            XOR: res = {1'b0, a ^ b};
            NOR: res = {1'b0, ~(a | b)};
            SLT: res = {32'b0, signed_a < signed_b};
            SLTU: res = {32'b0, a < b};
            SLL: res = {signed_a[31:0], 1'b0};
            SRL: res = {1'b0, signed_a[31:1]};
            SRA: res = {signed_a[31], signed_a[31:1]};
            SLLV: res = {signed_a[31:0], 1'b0};
            SRLV: res = {1'b0, signed_a[31:1]};
            SRAV: res = {signed_a[31], signed_a[31:1]};
            LUI: res = {b[15:0], 16'b0};
            default: res = 33'b0;
        endcase
    end

endmodule

module edge_detect (
    input clk,
    input rst_n,
    input a,
    output reg rise,
    output reg down
);

reg prev_a;

always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
        prev_a <= 1'b0; 
    end else begin
        prev_a <= a; 
    end
end

always @* begin
    if (prev_a == 1'b0 && a == 1'b1) begin
        rise = 1'b1; 
    end else if (prev_a == 1'b1 && a == 1'b0) begin
        down = 1'b1; 
    end else begin
        rise = 1'b0; 
        down = 1'b0; 
    end
end
endmodule

module instr_reg (
    input clk,
    input rst,
    input [1:0] fetch,
    input [7:0] data,
    output [2:0] ins,
    output [4:0] ad1,
    output [7:0] ad2
);
    reg [7:0] ins_p1, ins_p2;

    always@(posedge clk or negedge rst) begin
        if(!rst) begin
            ins_p1 <= 8'b0;
            ins_p2 <= 8'b0;
        end
        else begin
            case(fetch)
                2'b01: ins_p1 <= data;
                2'b10: ins_p2 <= data;
                default: begin
                    ins_p1 <= ins_p1;
                    ins_p2 <= ins_p2;
                end
            endcase
        end
    end

    assign ins = ins_p1[7:5];
    assign ad1 = ins_p1[4:0];
    assign ad2 = ins_p2;
endmodule

module up_down_counter (
    input wire clk,
    input wire reset,
    input wire up_down,
    output reg [15:0] count
);
    always @(posedge clk or posedge (reset)) begin
        if (reset) begin
            count <= 16'b0;
        end else if (up_down) begin
            count <= count + 1;
        end else begin
            count <= count - 1;
        end
    end
endmodule

module adder_16bit (
    input wire [15:0] a,
    input wire [15:0] b,
    input wire Cin,
    output wire [15:0] y,
    output wire Co
);

wire c1, c2;

assign {c1, y[7:0]} = a[7:0] + b[7:0] + Cin;
assign {c2, y[15:8]} = a[15:8] + b[15:8] + c1;

assign Co = c2;
endmodule

module add8 (
    input wire [7:0] a,
    input wire [7:0] b,
    input wire Cin,
    output wire [7:0] y,
    output wire Co
);

    wire Co_temp;

    add4 add4_inst1 (
        .a(a[7:4]),
        .b(b[7:4]),
        .Cin(Co_temp),
        .y(y[7:4]),
        .Co(Co)
    );

    add4 add4_inst2 (
        .a(a[3:0]),
        .b(b[3:0]),
        .Cin(Cin),
        .y(y[3:0]),
        .Co(Co_temp)
    );

endmodule

module add4 (
    input wire [3:0] a,
    input wire [3:0] b,
    input wire Cin,
    output wire [3:0] y,
    output wire Co
);

    wire Co_temp;

    add2 add2_inst1 (
        .a(a[3:2]),
        .b(b[3:2]),
        .Cin(Co_temp),
        .y(y[3:2]),
        .Co(Co)
    );

    add2 add2_inst2 (
        .a(a[1:0]),
        .b(b[1:0]),
        .Cin(Cin),
        .y(y[1:0]),
        .Co(Co_temp)
    ); 

endmodule

module add2 (
    input wire [1:0] a,
    input wire [1:0] b,
    input wire Cin,
    output wire [1:0] y,
    output wire Co
);

    wire Co_temp;

    add1 add1_inst1 (
        .a(a[1]),
        .b(b[1]),
        .Cin(Co_temp),
        .y(y[1]),
        .Co(Co)
    );

    add1 add1_inst2 (
        .a(a[0]),
        .b(b[0]),
        .Cin(Cin),
        .y(y[0]),
        .Co(Co_temp)
    );

endmodule

module add1 (
    input wire a,
    input wire b,
    input wire Cin,
    output wire y,
    output wire Co
);
    assign y = ((~a) & (~b) & Cin | (~a) & b & (~Cin) | a & (~b) & (~Cin) | (a & b & Cin));
    assign Co = ((~a & b & Cin) | (a & ~b & Cin) | (a & b & ~Cin) | (a & b & Cin));

endmodule

module multi_pipe_4bit #(
    parameter size = 4,
    parameter N = 2 * size
) (
    input 						clk,
    input 						rst_n,
    input	[size-1:0]			mul_a,
    input	[size-1:0]			mul_b,
    output	reg	[size*2-1:0]	mul_out
);

reg [size-1:0] a_reg, b_reg;
reg [N-1:0] partial_products [size-1:0];
reg [size:0] carry;

integer i;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        a_reg <= 0;
        b_reg <= 0;
        for (i = 0; i < size; i = i + 1) begin
            partial_products[i] <= 0;
        end
        carry <= 0;
        mul_out <= 0;
    end else begin
        a_reg <= mul_a;
        b_reg <= mul_b;
        partial_products[0] <= a_reg * b_reg[0];
        carry <= a_reg * b_reg[0] > 1 << size ? 1 : 0;
        for (i = 1; i < size; i = i + 1) begin
            partial_products[i] <= a_reg * b_reg[i] + carry;
            carry <= partial_products[i] > 1 << size ? 1 : 0;
        end
        mul_out <= {carry[size-1], partial_products[size-1:0]};
    end
end

endmodule

module verified_multi_pipe#(
	parameter size = 4
)(
	input 						clk 		,   
	input 						rst_n		,
	input	[size-1:0]			mul_a		,
	input	[size-1:0]			mul_b		,

 	output	reg	[size*2-1:0]	mul_out		
);

parameter N = 2 * size;

reg     [N-1:0]     sum_tmp1                ;
reg     [N-1:0]     sum_tmp2                ;
wire    [N-1:0]     mul_a_extend            ;
wire    [N-1:0]     mul_b_extend            ;

wire    [N-1:0]     mul_result[size-1:0]    ;

genvar i;
generate
    for(i = 0; i < size; i = i + 1) begin:add
        assign mul_result[i] = mul_b[i] ? mul_a_extend << i : 'd0;
    end
endgenerate

assign mul_a_extend = {{size{1'b0}}, mul_a};
assign mul_b_extend = {{size{1'b0}}, mul_b};

always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        sum_tmp1 <= 'd0;
        sum_tmp2 <= 'd0;
    end
    else begin
        sum_tmp1 <= mul_result[0] + mul_result[1];
        sum_tmp2 <= mul_result[2] + mul_result[3];
    end
end

always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        mul_out <= 'd0;
    end
    else begin
        mul_out <= sum_tmp1 + sum_tmp2;
    end
end

endmodule

module counter_12 (
    input rst_n,
    input clk,
    input valid_count,
    output reg [3:0] out
);
    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) 
            out <= 4'b0000;
        else if(valid_count==1) begin
            if(out == 4'd11) out <= 4'b0000; else out <= out + 1;
        end
    end

endmodule

module adder_bcd (
    input  [3:0] A,
    input  [3:0] B,
    input  Cin,
    output [3:0] Sum,
    output Cout
);

wire [4:0] temp_sum;
wire correction_needed;
wire [4:0] corrected_sum;

assign temp_sum = A + B + Cin;

assign correction_needed = (temp_sum > 5'b01001);

assign corrected_sum = temp_sum + (correction_needed ? 5'b00110 : 5'b00000);

assign Sum = corrected_sum[3:0];
assign Cout = corrected_sum[4];
endmodule

