    input [7:0] a,
    b,
    input cin,
    output [7:0] sum,
    output cout
);

    assign {cout, sum} = a + b + cin;
endmodule

module full_adder (input a, b, cin, output sum, cout);
    assign {cout, sum} = a + b + cin;
endmodule

module accu (
    input               clk,
    input               rst_n,
    input       [7:0]   data_in,
    input               valid_in,
    output  reg         valid_out,
    output  reg [9:0]   data_out
);
    reg [7:0] data_buf [3:0];
    reg [1:0] cnt;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            cnt <= 0;
            valid_out <= 0;
            data_out <= 0;
        end else if (valid_in) begin
            data_buf[cnt] <= data_in;
            cnt <= cnt + 1;
            if (cnt == 3) begin
                data_out <= data_buf[0] + data_buf[1] + data_buf[2] + data_buf[3];
                valid_out <= 1;
                cnt <= 0;
            end else begin
                valid_out <= 0;
            end
        end else begin
            valid_out <= 0;
        end
    end
endmodule

module freq_divbyeven #(
    parameter NUM_DIV = 6
) (
    input clk,
    input rst_n,
    output reg clk_div
);


reg [3:0] cnt;
reg clk_div_reg;

always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
        cnt <= 4'b0;
        clk_div_reg <= 1'b0;
    end else begin
        if (cnt < NUM_DIV/2 - 1) begin
            cnt <= cnt + 1;
        end else begin
            cnt <= 4'b0;
            clk_div_reg <= ~clk_div_reg;
        end
    end
end

assign clk_div = clk_div_reg;
endmodule

module LFSR (
    output reg [3:0] out,
    input clk,
    input rst
);
    reg [3:0] out_reg;
    wire feedback;

    assign feedback = ~(out_reg[3] ^ out_reg[2]);
    assign out = out_reg;
    always @(posedge clk or posedge rst) begin
        if(rst) begin
            out_reg <= 4'b0;
        end else begin
            out_reg <= {out_reg[2:0],feedback};
        end
    end

endmodule

module freq_divbyodd #(
    parameter NUM_DIV = 5
) (
    input clk,
    input rst_n,
    output reg clk_div
);
parameter HALF_DIV = NUM_DIV / 2;
parameter COUNTER_MAX = NUM_DIV - 1;

reg [3:0] cnt1, cnt2;
reg clk_div1, clk_div2;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        cnt1 <= 0;
        clk_div1 <= 0;
    end else begin
        if (cnt1 == HALF_DIV - 1) begin
            cnt1 <= 0;
            clk_div1 <= ~clk_div1;
        end else begin
            cnt1 <= cnt1 + 1;
        end
    end
end

always @(negedge clk or negedge rst_n) begin
    if (!rst_n) begin
        cnt2 <= 0;
        clk_div2 <= 0;
    end else begin
        if (cnt2 == HALF_DIV - 1) begin
            cnt2 <= 0;
            clk_div2 <= ~clk_div2;
        end else begin
            cnt2 <= cnt2 + 1;
        end
    end
end

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        clk_div <= 0;
    end else begin
        clk_div <= clk_div1 | clk_div2;
    end
end

endmodule

module ROM (
