);
    reg [15:0] mem [0:255];

    initial begin
        mem[0] = 16'hA0A0;
        mem[1] = 16'hB1B1;
        mem[2] = 16'hC2C2;
        mem[3] = 16'hD3D3;

    end

    assign dout = mem[addr];
endmodule

module JC_counter (
    input                clk,
    input                rst_n,
    output reg [63:0]     Q
);
    always @(posedge clk or negedge rst_n) begin
        if (~rst_n)
            Q <= 64'd0;
        else if (Q[0]==1'b0) Q <= {1'b1,Q[63:1]}; else Q <= {1'b0,Q[63:1]};
    end
endmodule

module RAM (
    input clk,
    input rst_n,
    input write_en,
    input [7:0]write_addr,
    input [5:0]write_data,
    input read_en,
    input [7:0]read_addr,
    output reg [5:0]read_data
);

	parameter WIDTH = 6;
	parameter DEPTH = 8;

	reg [DEPTH - 1 : 0] RAM [2**WIDTH-1:0];
	integer i;

	always@(posedge clk or negedge rst_n) begin
		if(!rst_n) begin
			for(i = 0; i < 2**WIDTH; i=i+1) begin
				RAM[i] <= 6'b000000;
			end
		end

		else if(write_en) begin
			RAM[write_addr] <= write_data;
		end
	end

	always@(posedge clk or negedge rst_n) begin
		if(!rst_n) begin
			read_data <= 6'b000000;
		end

		else if(read_en) begin
			read_data <= RAM[read_addr];
		end

		else begin
			read_data <= 6'b000000;
		end
	end
endmodule

module right_shifter (
    input clk,
    output reg [7:0] q,
    input d
);

initial begin
    q = 8'b00000000;
end

always @(posedge clk) begin
    q <= (q >> 1);
    q[7] <= d;
end
endmodule

module LIFObuffer (
    input [3:0] dataIn,
    input RW,
    input EN,
    input Rst,
    input Clk,
    output reg EMPTY,
    output reg FULL,
    output reg [3:0] dataOut
);

    reg [3:0] stack_mem [0:3];
    reg [1:0] SP;

    always @(posedge Clk) begin
        if (EN) begin
            if (Rst) begin
                SP <= 2'b100;
                EMPTY <= 1'b1;
                FULL <= 1'b0;
                dataOut <= 4'b0;
                stack_mem[0] <= 4'b0;
                stack_mem[1] <= 4'b0;
                stack_mem[2] <= 4'b0;
                stack_mem[3] <= 4'b0;
            end
            else begin
                if (!FULL && !EMPTY) begin
                    if (RW) begin
                        dataOut <= stack_mem[SP];
                        stack_mem[SP] <= 4'b0;
                        SP <= SP + 1;
                        if (SP == 2'b100) begin
                            EMPTY <= 1'b1;
                        end
                        FULL <= 1'b0;
                    end
                    else begin
                        stack_mem[SP] <= dataIn;
                        SP <= SP - 1;
                        EMPTY <= 1'b0;
                        if (SP == 2'b011) begin
                            FULL <= 1'b1;
                        end
                    end
                end
                else if (!EMPTY) begin
                    dataOut <= stack_mem[SP];
                    stack_mem[SP] <= 4'b0;
                    SP <= SP + 1;
                    if (SP == 2'b100) begin
                        EMPTY <= 1'b1;
                    end
                    FULL <= 1'b0;
                end
                else if (!FULL) begin
                    stack_mem[SP] <= dataIn;
                    SP <= SP - 1;
                    EMPTY <= 1'b0;
                    if (SP == 2'b011) begin
                        FULL <= 1'b1;
                    end
                end
            end
        end
    end

endmodule

module synchronizer (
    input 				clk_a,
    input 				clk_b,
    input 				arstn,
    input				brstn,
    input		[3:0]	data_in,
    input               data_en,
    output reg  [3:0] 	dataout
);

reg [3:0] data_reg;
always@(posedge clk_a or negedge arstn) begin
	if(!arstn) data_reg <= 4'b0; else data_reg <= data_in;
end

reg en_data_reg;
always@(posedge clk_a or negedge arstn) begin
	if(!arstn) en_data_reg <= 1'b0; else en_data_reg <= data_en;
end

reg en_clap_one, en_clap_two;
always@(posedge clk_b or negedge brstn) begin
	if(!brstn) begin
		en_clap_one <= 1'b0;
		en_clap_two <= 1'b0;
	end
	else begin
		en_clap_one <= en_data_reg;
		en_clap_two <= en_clap_one;
	end
end

reg [3:0] dataout_reg;
always@(posedge clk_b or negedge brstn) begin
	if(!brstn) 
		dataout_reg <= 4'b0;
	else if(en_clap_two) dataout_reg <= data_reg; else dataout_reg <= dataout_reg;
end
assign dataout = dataout_reg;
endmodule
